def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    for i, capacity in enumerate(bins):
        if capacity <= 0:
            priorities[i] = np.inf
            continue
        usage_ratio = item / capacity
        priority = 0.0
        if usage_ratio > 1:
            priority += 1000 * usage_ratio
        elif usage_ratio == 1:
            priority += 100
        else:
            try:
                log_val = np.log(1 - usage_ratio + 1e-12)
            except FloatingPointError:
                log_val = -np.inf
            if log_val < -1:
                priority += -log_val * 7
            else:
                priority += -log_val * 1.5
            extra_factor = 0
            for j in range(1, 4):
                power = usage_ratio ** j
                if power < 0.5:
                    extra_factor += power * 10 / j
                else:
                    extra_factor += (1 - power) * 7 / (j + 1)
            priority += extra_factor
        if capacity < 0.05:
            priority += 70
            if usage_ratio > 0.75:
                priority += 30
        elif capacity < 0.5:
            priority += 20
            if usage_ratio > 0.9:
                priority += 15
        else:
            if usage_ratio < 0.3:
                priority -= 5
            elif usage_ratio > 0.8:
                priority += 25
        proximity_score = 0
        if capacity % 2 == 0:
            proximity_score += 3
        if int(capacity * 10) % 3 == 0:
            proximity_score -= 2
        for k in range(1, 3):
            if abs(usage_ratio - k/3) < 0.05:
                proximity_score += 10 / k
        priority += proximity_score
        priorities[i] = priority
    return priorities
